function Search({ searchValue, setSearchValue }) {
  return (
    <Box sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
      <OutlinedInput
        size="small"
        id="search"
        placeholder="Search…"
        value={searchValue}
        onChange={(e) => setSearchValue(e.target.value)}
        sx={{ flexGrow: 1,color:"white",border }}
        startAdornment={
          <InputAdornment position="start" sx={{ color: 'text.primary' }}>
            <SearchRoundedIcon fontSize="small" />
          </InputAdornment>
        }
        inputProps={{
          'aria-label': 'search',
        }}
      />
    </Box>
  );
}

export default function Projects() {
  const [selectedCategory, setSelectedCategory] = React.useState('All');
  const [searchValue, setSearchValue] = React.useState('');

  // Get unique categories from cardData
  const categories = ['All', ...new Set(cardData.map((card) => card.category))];

  // Filter cards based on selected category and search input
  const filteredCards = cardData.filter(card => {
    const matchesCategory = selectedCategory === 'All' || card.category === selectedCategory;
    const matchesSearch = card.title.toLowerCase().includes(searchValue.toLowerCase()) || 
                          card.description.toLowerCase().includes(searchValue.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap:2 }}>
         <div className="section-header">
        <h2 style={{ color: '#fff' }}>
          <span className="accent">#</span> Projects
        </h2>
      </div>
      <Box
        sx={{
          display: { xs: 'flex', sm: 'none' },
          flexDirection: 'row',
          gap: 1,
          width: { xs: '100%', md: 'fit-content' },
          overflow: 'auto',
        }}
      >
        <Search searchValue={searchValue} setSearchValue={setSearchValue} />
        <IconButton size="small" aria-label="RSS feed">
          <RssFeedRoundedIcon />
        </IconButton>
      </Box>
      <Box
        sx={{
          display: 'flex',
          flexDirection: { xs: 'column-reverse', md: 'row' },
          width: '100%',
          justifyContent: 'space-between',
          alignItems: { xs: 'start', md: 'center' },
          gap: 3,
          overflow: 'auto',
        }}
      >
        <Box
          sx={{
            display: 'inline-flex',
            flexDirection: 'row',
            gap: 2,
            overflow: 'auto',
          }}
        >
          {categories.map(category => (
            <Chip
